-/// Protocol used by Commander property wrappers to convert string arguments into typed values.
-public protocol ExpressibleFromArgument {
-    init?(argument: String)
-}
-
-extension String: ExpressibleFromArgument {
-    public init?(argument: String) { self = argument }
-}
-
-extension Substring: ExpressibleFromArgument {
-    public init?(argument: String) { self = Substring(argument) }
-}
-
-extension Int: ExpressibleFromArgument {
-    public init?(argument: String) { self.init(argument, radix: 10) }
-}
-
-extension Int32: ExpressibleFromArgument {
-    public init?(argument: String) { self.init(argument, radix: 10) }
-}
-
-extension Int64: ExpressibleFromArgument {
-    public init?(argument: String) { self.init(argument, radix: 10) }
-}
-
-extension Double: ExpressibleFromArgument {
-    public init?(argument: String) { self.init(argument) }
-}
-
-extension Bool: ExpressibleFromArgument {
-    public init?(argument: String) {
-        let lowered = argument.lowercased()
-        switch lowered {
-        case "true", "t", "1", "yes", "y":
-            self = true
-        case "false", "f", "0", "no", "n":
-            self = false
-        default:
-            return nil
-        }
-    }
-}

@@ -1,122 +0,0 @@
-import Foundation
-
-public struct ParsedValues: Sendable, Equatable {
-    public var positional: [String]
-    public var options: [String: [String]]
-    public var flags: Set<String>
-}
-
-struct CommandParser {
-    let signature: CommandSignature
-
-    func parse(arguments: [String]) throws -> ParsedValues {
-        let tokens = CommandLineTokenizer.tokenize(arguments)
-        var positional: [String] = []
-        var options: [String: [String]] = [:]
-        var flags = Set<String>()
-
-        let optionLookup = Self.buildOptionLookup(signature.options)
-        let flagLookup = Self.buildFlagLookup(signature.flags)
-
-        var index = 0
-        while index < tokens.count {
-            let token = tokens[index]
-            index += 1
-            switch token {
-            case .option(let name):
-                if let definition = optionLookup[name] {
-                    var consumed: [String] = []
-                    switch definition.parsing {
-                    case .singleValue:
-                        guard index < tokens.count else {
-                            throw CommanderError.missingValue(option: name)
-                        }
-                        if case let .argument(value) = tokens[index] {
-                            consumed.append(value)
-                            index += 1
-                        } else {
-                            throw CommanderError.missingValue(option: name)
-                        }
-                    case .upToNextOption:
-                        parsingLoop: while index < tokens.count {
-                            switch tokens[index] {
-                            case .argument(let value):
-                                consumed.append(value)
-                                index += 1
-                            case .terminator:
-                                index += 1
-                                while index < tokens.count {
-                                    if case let .argument(value) = tokens[index] {
-                                        consumed.append(value)
-                                    }
-                                    index += 1
-                                }
-                                break parsingLoop
-                            case .option, .flag:
-                                break parsingLoop
-                            }
-                        }
-                    case .remaining:
-                        while index < tokens.count {
-                            if case let .argument(value) = tokens[index] {
-                                consumed.append(value)
-                            }
-                            index += 1
-                        }
-                    }
-                    options[definition.label, default: []].append(contentsOf: consumed)
-                } else if let flagLabel = flagLookup[name] {
-                    flags.insert(flagLabel)
-                } else {
-                    throw CommanderError.unknownOption("--" + name)
-                }
-            case .flag(let name):
-                guard let flagLabel = flagLookup[name] else {
-                    throw CommanderError.unknownOption("-" + name)
-                }
-                flags.insert(flagLabel)
-            case .argument(let value):
-                positional.append(value)
-            case .terminator:
-                while index < tokens.count {
-                    if case let .argument(value) = tokens[index] {
-                        positional.append(value)
-                    }
-                    index += 1
-                }
-            }
-        }
-
-        return ParsedValues(positional: positional, options: options, flags: flags)
-    }
-
-    private static func buildOptionLookup(_ definitions: [OptionDefinition]) -> [String: OptionDefinition] {
-        var lookup: [String: OptionDefinition] = [:]
-        for definition in definitions {
-            for name in definition.names {
-                switch name {
-                case .long(let longName):
-                    lookup[longName] = definition
-                case .short(let shortName):
-                    lookup[String(shortName)] = definition
-                }
-            }
-        }
-        return lookup
-    }
-
-    private static func buildFlagLookup(_ definitions: [FlagDefinition]) -> [String: String] {
-        var lookup: [String: String] = [:]
-        for definition in definitions {
-            for name in definition.names {
-                switch name {
-                case .long(let longName):
-                    lookup[longName] = definition.label
-                case .short(let shortName):
-                    lookup[String(shortName)] = definition.label
-                }
-            }
-        }
-        return lookup
-    }
-}

@@ -1,33 +0,0 @@
-import Foundation
-
-enum Token: Equatable, Sendable {
-    case option(name: String)
-    case flag(name: String)
-    case argument(String)
-    case terminator
-}
-
-struct CommandLineTokenizer {
-    static func tokenize(_ argv: [String]) -> [Token] {
-        var result: [Token] = []
-        var iterator = argv.makeIterator()
-        while let segment = iterator.next() {
-            if segment == "--" {
-                result.append(.terminator)
-                result.append(contentsOf: iterator.map { .argument($0) })
-                break
-            } else if segment.hasPrefix("--") {
-                let name = String(segment.dropFirst(2))
-                result.append(.option(name: name))
-            } else if segment.hasPrefix("-") && segment.count > 1 {
-                let chars = segment.dropFirst()
-                for char in chars {
-                    result.append(.flag(name: String(char)))
-                }
-            } else {
-                result.append(.argument(segment))
-            }
-        }
-        return result
-    }
-}

